// ── 책 등 생성 ──
const spine = document.getElementById('spine');
for (let i = 0; i < TOTAL_PAGES; i++) {
  const s = document.createElement('div');
  s.className = 'spine-section'; s.id = `sp${i}`;
  spine.appendChild(s);
}

function updateSpine() {}

// ── 페이지 이동 ──
function go(to, dir) {
  if (animating || to === cur || to < 0 || to > 9) return;
  animating = true;

  const fromEl = document.getElementById(`p${cur}`);
  const toEl   = document.getElementById(`p${to}`);

  // 로딩→결과: 페이드
  if (cur === 8 && to === 9) {
    fromEl.style.transition = 'opacity .5s ease';
    fromEl.style.opacity = '0';
    setTimeout(() => {
      fromEl.classList.remove('active');
      fromEl.style.opacity = ''; fromEl.style.transition = '';
      renderResult();
      toEl.classList.add('active');
      toEl.style.opacity = '0'; toEl.style.transition = 'opacity .5s ease';
      requestAnimationFrame(() => requestAnimationFrame(() => { toEl.style.opacity = '1'; }));
      setTimeout(() => { toEl.style.opacity=''; toEl.style.transition=''; animating=false; }, 500);
      cur = 9; updateSpine();
    }, 500);
    return;
  }

  // 두 페이지 동시 애니메이션
  // 다음 페이지 콘텐츠 준비
  if (to === 8) startLoading();
  if (to === 9) renderResult();
  cur = to; updateSpine();

  // Phase 1: 현재 페이지 접힘 — toEl은 아직 숨김
  toEl.classList.add('active');
  toEl.style.opacity = '0';
  toEl.style.zIndex = '1';
  fromEl.style.zIndex = '2';
  fromEl.classList.add(`page-exit-${dir}`);

  setTimeout(() => {
    fromEl.classList.remove('active', `page-exit-${dir}`);
    fromEl.style.zIndex = '';
    toEl.style.zIndex = '';
    // Phase 2: 다음 페이지 펼쳐짐 (90deg → 0) — 애니메이션 시작 후 opacity 복원
    toEl.classList.add(`page-enter-${dir}`);
    requestAnimationFrame(() => { toEl.style.opacity = ''; });
    setTimeout(() => {
      toEl.classList.remove(`page-enter-${dir}`);
      animating = false;
    }, 900);
  }, 900);
}

function pick(qi, val, pi) {
  ans[qi] = val;
  document.querySelectorAll(`[data-qi="${qi}"]`)
    .forEach(b => b.classList.toggle('selected', +b.dataset.v === val));
  const nxt = document.getElementById(`nxt${pi}`);
  if (nxt) nxt.disabled = false;
  setTimeout(() => { if (cur === pi) go(pi + 1, 'fwd'); }, 480);
}

// ── 건너뛰기: 로딩 없이 바로 결과 ──
function skipToResult() {
  computeResult();
  go(9, 'fwd');
}

// ── 재시작 ──
function restart() {
  ans.fill(null);
  shakeCount = 0;
  clearTimeout(loadingTimer);
  document.querySelectorAll('.choice-btn').forEach(b => b.classList.remove('selected'));
  for (let i = 2; i <= 7; i++) {
    const n = document.getElementById(`nxt${i}`);
    if (n) n.disabled = true;
  }
  const p9 = document.getElementById('p9');
  p9.scrollTop = 0;
  go(0, 'bwd');
}

// ── 로딩 화면 ──
const mkglList = ['mkgl_anjunsaeng','mkgl_gureum','mkgl_haechang','mkgl_haenam','mkgl_jipyeong','mkgl_kongmak','mkgl_omija','mkgl_sagubae','mkgl_wangbam','mkgl_yuja'];
function startLoading() {
  shakeCount = 0;
  const bowl = document.getElementById('loadingBowl');
  bowl.src = 'images/' + mkglList[Math.floor(Math.random() * mkglList.length)] + '.png';
  computeResult();
  loadingTimer = setTimeout(() => { if (cur === 8) go(9, 'fwd'); }, 4000);
}

function shakeBowl(e) {
  const bowl = document.getElementById('loadingBowl');
  const wrap = document.getElementById('bowlWrap');

  // 파문 이펙트
  const r = document.createElement('div');
  r.className = 'ripple';
  r.style.cssText = `left:${50 - 40}px;top:${35 - 40}px;`;
  bowl.parentElement.style.position = 'relative';
  bowl.parentElement.appendChild(r);
  setTimeout(() => r.remove(), 700);

  // 기울기 토글
  bowl.classList.remove('tilt-l', 'tilt-r');
  void bowl.offsetWidth;
  bowl.classList.add(shakeCount % 2 === 0 ? 'tilt-l' : 'tilt-r');
  // 탭 후 자동흔들기로 복귀
  setTimeout(() => { bowl.classList.remove('tilt-l', 'tilt-r'); }, 400);

  shakeCount++;
  if (shakeCount >= 4) {
    clearTimeout(loadingTimer);
    bowl.classList.remove('tilt-l', 'tilt-r');
    setTimeout(() => { if (cur === 8) go(9, 'fwd'); }, 500);
  }
}

// ── 결과 계산 ──
let computedType = null;

function computeResult() {
  const scores = [0, 0, 0, 0];
  SCORES.forEach((q, i) => {
    if (ans[i] !== null) q[ans[i]].forEach((s, j) => scores[j] += s);
  });
  const max = Math.max(...scores);
  computedType = TYPES[scores.indexOf(max)];
}

// ── 결과 렌더링 ──
function renderResult() {
  if (!computedType) computeResult();
  const d = RESULT_DATA[computedType];
  const idx = TYPES.indexOf(computedType);

  // 4탭 active
  TYPES.forEach((_, i) => document.getElementById(`rt${i}`).classList.toggle('on', i === idx));

  document.getElementById('rTitle').textContent = d.title;
  document.getElementById('rSub').textContent   = d.sub;
  document.getElementById('rDesc').textContent  = d.desc;

  // 결과 대표 이미지
  const rImg = document.getElementById('rImg');
  rImg.innerHTML = `<img src="${d.img}" alt="${d.title}" style="width:100%;height:100%;object-fit:contain;">`;

  // 막걸리 목록
  document.getElementById('rMkgl').innerHTML = d.mkgl.map(m => `
    <div class="mkgl-item${m.ft?' featured':''}">
      <div class="mkgl-bottle">
        <img src="${m.img}" alt="${m.n}" style="width:100%;height:100%;object-fit:contain;${m.sm?'transform:scale(0.72);':''}">
      </div>
      <p class="mkgl-name">${m.n}</p>
    </div>`).join('');

  // 안주 페어링
  document.getElementById('rFood').innerHTML = d.food.map(f => `
    <div class="food-item${f.ft?' featured':''}">
      <div class="food-plate">
        <img src="${f.img}" alt="${f.n}" style="width:100%;height:100%;object-fit:contain;">
      </div>
      <p class="food-name">${f.n}</p>
    </div>`).join('');
  setupSwipeCarousel('rMkgl');
  setupSwipeCarousel('rFood');
}


function setupSwipeCarousel(rowId) {
  const row = document.getElementById(rowId);
  if (!row || row._swipeReady) return;
  row._swipeReady = true;

  let startX = 0, startY = 0, lockAxis = null;

  row.addEventListener('touchstart', e => {
    startX = e.touches[0].clientX;
    startY = e.touches[0].clientY;
    lockAxis = null;
    row.style.transition = 'none';
  }, { passive: true });

  row.addEventListener('touchmove', e => {
    const dx = e.touches[0].clientX - startX;
    const dy = e.touches[0].clientY - startY;

    if (!lockAxis) {
      lockAxis = Math.abs(dx) > Math.abs(dy) ? 'x' : 'y';
    }
    if (lockAxis !== 'x') return;

    // 손가락을 실시간으로 따라오되 약간 저항감 줌
    row.style.transform = `translateX(${dx * 0.55}px)`;
  }, { passive: true });

  row.addEventListener('touchend', e => {
    const dx = e.changedTouches[0].clientX - startX;
    const dy = e.changedTouches[0].clientY - startY;

    if (lockAxis !== 'x' || Math.abs(dx) < 40) {
      // 임계값 미달 → 원위치로 스냅
      row.style.transition = 'transform .3s cubic-bezier(.25,.46,.45,.94)';
      row.style.transform = '';
      setTimeout(() => { row.style.transition = ''; }, 300);
      return;
    }

    const items = [...row.children];
    const mid = Math.floor(items.length / 2);

    if (dx > 0) {
      row.insertBefore(items[items.length - 1], items[0]);
    } else {
      row.appendChild(items[0]);
    }

    [...row.children].forEach((el, i) =>
      el.classList.toggle('featured', i === mid)
    );

    // 반대편에서 자연스럽게 스냅
    const overshoot = dx > 0 ? -20 : 20;
    row.style.transition = 'none';
    row.style.transform = `translateX(${overshoot}px)`;
    requestAnimationFrame(() => requestAnimationFrame(() => {
      row.style.transition = 'transform .32s cubic-bezier(.25,.46,.45,.94)';
      row.style.transform = '';
      setTimeout(() => { row.style.transition = ''; }, 320);
    }));
  }, { passive: true });
}

updateSpine();


